<span class="line">    <span class="token keyword">return</span> path<span class="token punctuation">[</span><span class="token punctuation">(</span>lastSlash <span class="token operator">+</span> <span class="token number">1</span><span class="token punctuation">)</span><span class="token range operator">..</span><span class="token punctuation">]</span><span class="token punctuation">;</span></span>
